import httpx
import json
import re
from langflow.custom import Component
from langflow.io import MessageInput, Output
from langflow.schema.message import Message

class Primer3DesignComponent(Component):
    display_name = "Primer3 Design"
    description = "Sends alignment JSON to the Primer3 design service"

    inputs = [
        MessageInput(name="alignment_json", display_name="Alignment JSON"),
    ]
    outputs = [
        Output(display_name="Primer Results", name="results", method="run"),
    ]

    def _extract_json(self, text: str) -> dict:
        text = text.strip()
        if text.startswith("```"):
            text = re.sub(r"^```(?:json)?\s*\n?", "", text)
            text = re.sub(r"\n?```\s*$", "", text)
            text = text.strip()
        try:
            return json.loads(text)
        except json.JSONDecodeError:
            pass
        match = re.search(r"\{", text)
        if match:
            depth = 0
            in_string = False
            escape = False
            start = match.start()
            for i in range(start, len(text)):
                c = text[i]
                if escape:
                    escape = False
                    continue
                if c == "\\":
                    escape = True
                    continue
                if c == '"' and not escape:
                    in_string = not in_string
                    continue
                if in_string:
                    continue
                if c == "{":
                    depth += 1
                elif c == "}":
                    depth -= 1
                    if depth == 0:
                        candidate = text[start:i + 1]
                        try:
                            return json.loads(candidate)
                        except json.JSONDecodeError:
                            break
        raise ValueError(f"Could not parse as JSON. First 500 chars: {text[:500]}")

    def _get_text(self, raw) -> str:
        """Try every way to get text content from the input."""
        candidates = []

        if isinstance(raw, Message):
            for attr in ("text", "content", "data", "result", "message"):
                val = getattr(raw, attr, None)
                if val and isinstance(val, str) and val.strip():
                    candidates.append(("Message." + attr, val))
            if hasattr(raw, "dict"):
                try:
                    d = raw.dict() if callable(raw.dict) else raw.dict
                    candidates.append(("Message.dict()", json.dumps(d)))
                except Exception:
                    pass
        elif isinstance(raw, dict):
            candidates.append(("dict", json.dumps(raw)))
        elif isinstance(raw, str) and raw.strip():
            candidates.append(("str", raw))

        if not candidates:
            diag = {
                "type": type(raw).__name__,
                "dir": [a for a in dir(raw) if not a.startswith("_")],
                "str_repr": str(raw)[:500],
            }
            if isinstance(raw, Message):
                diag["text_value"] = repr(getattr(raw, "text", None))
                diag["data_value"] = repr(getattr(raw, "data", None))
            raise ValueError(json.dumps(diag, indent=2, default=str))

        return candidates[0][1]

    def run(self) -> Message:
        raw = self.alignment_json

        try:
            text = self._get_text(raw)
        except ValueError as e:
            return Message(text=json.dumps({
                "error": "Could not extract text from input",
                "diagnostics": str(e)
            }, indent=2))

        try:
            data = self._extract_json(text)
        except (json.JSONDecodeError, ValueError) as e:
            return Message(text=json.dumps({
                "error": f"Failed to parse LLM JSON: {e}",
                "raw_preview": text[:500]
            }, indent=2))

        try:
            response = httpx.post(
                "http://127.0.0.1:8001/design-from-alignment",
                json=data,
                timeout=60.0,
            )
            response.raise_for_status()
            return Message(text=json.dumps(response.json(), indent=2))
        except httpx.HTTPStatusError as e:
            return Message(text=json.dumps({
                "error": f"Primer3 API returned {e.response.status_code}",
                "detail": e.response.text[:500]
            }, indent=2))
        except httpx.ConnectError:
            return Message(text=json.dumps({
                "error": "Cannot connect to Primer3 service at http://127.0.0.1:8001"
            }, indent=2))

